library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity Key_Expansion is
    Port (
        clk         : in  std_logic;
        rst         : in  std_logic;
        start       : in  std_logic;

        key_master  : in  std_logic_vector(255 downto 0);

        keyk0_out   : out std_logic_vector(127 downto 0);
        keyk1_out   : out std_logic_vector(127 downto 0);
        key_post    : out std_logic_vector(127 downto 0);

        key_index   : out std_logic_vector(3 downto 0);
        valid       : out std_logic;
		done        : out std_logic
    );
end Key_Expansion;

architecture Behavioral of Key_Expansion is
    component Gen_Key
        Port(
            clk        : in  std_logic;
            data_in    : in  std_logic_vector(127 downto 0);
            data_out   : out std_logic_vector(127 downto 0)
        );
    end component;

    function const_func(k, r : integer) return std_logic_vector is
        variable p_last : std_logic_vector(127 downto 0);
        variable p      : std_logic_vector(7 downto 0);
    begin
        if k = 0 then
            p := std_logic_vector(to_unsigned(2*r + 2, 8));
        elsif k = 1 then
            p := std_logic_vector(to_unsigned(2*r + 1, 8));
        else
            p := (others => '0');
        end if;
        p_last := (119 downto 0 => '0') & p;
        return p_last;
    end function;

    type state_type is (IDLE, INIT_K0, WAIT_K0, SAVE_K0, INIT_K1, WAIT_K1, SAVE_K1, UPDATE_K, NEXT_ROUND, FINISH);
    signal state	: state_type := IDLE;

    signal round	: unsigned(3 downto 0) := (others => '0');

    signal k0_reg : std_logic_vector(127 downto 0) := (others => '0');
    signal k1_reg : std_logic_vector(127 downto 0) := (others => '0');

    signal i_data_reg	: std_logic_vector(127 downto 0) := (others => '0'); 
    signal o_data_reg0, o_data_reg1, o_data	:    std_logic_vector(127 downto 0) := (others => '0');

begin
    GKEY : Gen_Key port map(clk => clk, data_in  => i_data_reg, data_out => o_data);
    process(clk, rst)
    begin
        if rst = '1' then
            state			<= IDLE;
            round		<= (others => '0');
			done			<= '0';			
            k0_reg <= (others => '0');
            k1_reg <= (others => '0');			
			i_data_reg<= (others => '0');
            o_data_reg0 <= (others => '0');
            o_data_reg1 <= (others => '0');   
            keyk0_out <= (others => '0');
            keyk1_out <= (others => '0');
            key_post  <= (others => '0');
            key_index <= (others => '0');
            valid     <= '0';      
        elsif rising_edge(clk) then
			valid        <= '0';
			case state is
				when IDLE =>
					if start = '1' then
						round 	<= "0001";
						k0_reg 	<= key_master(255 downto 128);
						k1_reg 	<= key_master(127 downto 0);
						state <= INIT_K0;
					end if;
				when INIT_K0 =>
					if round = "0001" then
						i_data_reg <= key_master(255 downto 128) xor std_logic_vector(to_unsigned(1, 128));
					else
						i_data_reg <= k0_reg xor const_func(1, to_integer(round)-1);
					end if;					
					state <= WAIT_K0;
				when WAIT_K0 =>                    
                    state <= SAVE_K0;
				when SAVE_K0 =>					
                    o_data_reg0 	<= o_data;
					state <= INIT_K1;
				when INIT_K1 =>
					if round = "0001" then
						i_data_reg <= key_master(127 downto 0) xor std_logic_vector(to_unsigned(2, 128));
					else
						i_data_reg <= k1_reg xor const_func(0, to_integer(round)-1);
					end if;										
					state <= WAIT_K1;
				when WAIT_K1 =>	
					state <= SAVE_K1;	
				when SAVE_K1 =>					
					o_data_reg1 	<= o_data;
					state <= UPDATE_K;             
				when UPDATE_K =>
                    key_index <= std_logic_vector(round - 1);                
                    if round = "0001" then
                        keyk0_out <= key_master(255 downto 128);
                    else
                        keyk0_out <= k1_reg;
                    end if;                
                    keyk1_out <= o_data_reg1;                
                    if round = "1001" then
                        key_post <= o_data_reg1 xor o_data_reg0;
                    end if;                
                    valid <= '1';                
                    state <= NEXT_ROUND;
				when NEXT_ROUND =>
				    k0_reg <= o_data_reg1;
                    k1_reg <= o_data_reg1 xor o_data_reg0;                
                    if round = "1001" then
                        done <= '1';
                        state <= FINISH;
                    else
                        round <= round + 1;
                        state <= INIT_K0;
                    end if;
				when FINISH =>
					if start = '0' then
						state <= IDLE;
					end if;
			end case;
        end if;
    end process;
end Behavioral;

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity decrypt is
    Port (
        clk         : in  std_logic;
        rst         : in  std_logic;
        start       : in  std_logic;

        ciphertext  : in  std_logic_vector(127 downto 0);

        keyk0       : in  std_logic_vector(127 downto 0);
        keyk1       : in  std_logic_vector(127 downto 0);
        key_post    : in  std_logic_vector(127 downto 0);

        next_round  : out std_logic;
        done        : out std_logic;
        plaintext   : out std_logic_vector(127 downto 0)
    );
end decrypt;

architecture Behavioral of decrypt is

    component INV_N_ROUND
        Port (
            data_in   : in  std_logic_vector(127 downto 0);
            keyk0     : in  std_logic_vector(127 downto 0);
            keyk1     : in  std_logic_vector(127 downto 0);
            data_out  : out std_logic_vector(127 downto 0)
        );
    end component;

    type state_type is (IDLE, LOAD, ROUND, NEXT_KEY, FINISH);

    signal state      : state_type := IDLE;
    signal sel_reg    : unsigned(3 downto 0) := (others => '0');

    signal data_reg   : std_logic_vector(127 downto 0);
    signal round_out  : std_logic_vector(127 downto 0);

begin

    ROUND_CORE : INV_N_ROUND
    port map(
        data_in  => data_reg,
        keyk0    => keyk0,
        keyk1    => keyk1,
        data_out => round_out
    );

    process(clk, rst)
    begin
        if rst='1' then
            state       <= IDLE;
            sel_reg     <= (others=>'0');
            data_reg    <= (others=>'0');
            plaintext   <= (others=>'0');
            done        <= '0';
            next_round  <= '0';

        elsif rising_edge(clk) then

            done <= '0';

            case state is

                when IDLE =>
                    sel_reg <= (others=>'0');

                    if start='1' then
                        state <= LOAD;
                    end if;

                when LOAD =>
                    -- Undo final whitening
                    data_reg <= ciphertext xor key_post;
                    state <= ROUND;

                when ROUND =>
                    next_round <= '1';
                    state <= NEXT_KEY;

                when NEXT_KEY =>
                    next_round <= '0';
                    data_reg <= round_out;

                    if sel_reg = 8 then
                        plaintext <= round_out;
                        done <= '1';
                        state <= FINISH;
                    else
                        sel_reg <= sel_reg + 1;
                        state <= ROUND;
                    end if;

                when FINISH =>
                    if start='0' then
                        state <= IDLE;
                    end if;

            end case;

        end if;
    end process;

end Behavioral;

